// B.5 benchmark — Woodward-Colella double blast waves (1D, strong shocks)
//
// Classic robustness test for compressible flow solvers under very high
// pressure ratios (10⁵:1) and multiple shock-shock / shock-contact
// interactions.  Two strong shocks generated by the left (p=1000) and right
// (p=100) high-pressure regions interact near x ≈ 0.6 and bounce between
// the reflecting walls.
//
// Reference: Woodward & Colella (1984) J. Comput. Phys. 54, 115–173.
//            Converged solution: ρ_max ≈ 6.0 at x ≈ 0.63, t = 0.038.
//
// Setup:
//   Domain [0, 1], BCType::Wall (both ends reflect)
//   ρ = 1 everywhere,  u = 0
//   p(x) = 1000    for x < 0.1
//          0.01    for 0.1 ≤ x < 0.9
//          100     for x ≥ 0.9
//   Level-3 uniform refinement → 64 cells in x, h ≈ 0.015625
//
// Gate criteria:
//   B5a  Peak density ρ_max > 3.0  (blast wave interaction has occurred)
//   B5b  x-location of ρ_max ∈ [0.35, 0.85]  (matches reference region)
//   B5c  No negative pressure  (robustness at 10⁵ pressure ratio)
//   B5d  Mass conservation  |Δm|/m₀ < 1e-10  (closed domain, wall BCs)

#include "../include/ns_solver.hpp"
#include <cstdio>
#include <cmath>
#include <vector>
#include <algorithm>

static int n_pass = 0, n_fail = 0;
static void check(const char* name, bool ok, double got = -1, double thr = -1)
{
    if (ok) { printf("  PASS  %s\n", name); ++n_pass; }
    else {
        if (got >= 0)
            printf("  FAIL  %s  (got %.3e  thr %.3e)\n", name, got, thr);
        else
            printf("  FAIL  %s\n", name);
        ++n_fail;
    }
}

static void fill_leaves(NSSolver& s,
    const std::function<Prim(double,double,double)>& ic)
{
    for (int li : s.tree.leaf_indices()) {
        auto& blk = *s.tree.nodes[li].block;
        for (int k = 0; k < NB2; ++k)
        for (int j = 0; j < NB2; ++j)
        for (int i = 0; i < NB2; ++i) {
            double x = blk.ox + (i - NG + 0.5) * blk.h;
            double y = blk.oy + (j - NG + 0.5) * blk.h;
            double z = blk.oz + (k - NG + 0.5) * blk.h;
            Prim p   = ic(x, y, z);
            int  idx = cell_idx(i, j, k);
            blk.Q[0][idx] = p.rho;
            blk.Q[1][idx] = p.rho * p.u;
            blk.Q[2][idx] = p.rho * p.v;
            blk.Q[3][idx] = p.rho * p.w;
            blk.Q[4][idx] = p.p / (GAMMA - 1.0)
                           + 0.5 * p.rho * (p.u*p.u + p.v*p.v + p.w*p.w);
        }
    }
}

struct CellSample { double x, rho, p_gas; };

static std::vector<CellSample> x_profile(const NSSolver& s)
{
    std::vector<CellSample> pts;
    const int jc = NG + NB / 2;
    const int kc = NG + NB / 2;
    for (int li : s.tree.leaf_indices()) {
        auto& blk = *s.tree.nodes[li].block;
        for (int i = NG; i < NG + NB; ++i) {
            double xc  = blk.ox + (i - NG + 0.5) * blk.h;
            int    idx = cell_idx(i, jc, kc);
            double rho = blk.Q[0][idx];
            double KE  = 0.5 * (blk.Q[1][idx]*blk.Q[1][idx]
                               + blk.Q[2][idx]*blk.Q[2][idx]
                               + blk.Q[3][idx]*blk.Q[3][idx]) / rho;
            double pg  = (GAMMA - 1.0) * (blk.Q[4][idx] - KE);
            pts.push_back({xc, rho, pg});
        }
    }
    std::sort(pts.begin(), pts.end(), [](const CellSample& a, const CellSample& b){
        return a.x < b.x;
    });
    return pts;
}

// ─────────────────────────────────────────────────────────────────────────────
static void b5_woodward_colella()
{
    printf("\n-- B5  Woodward-Colella double blast waves (Woodward & Colella 1984) --\n");

    const double L = 1.0;

    auto wc_ic = [](double xc, double, double) -> Prim {
        Prim q;
        q.rho = 1.0; q.u = 0.0; q.v = 0.0; q.w = 0.0;
        if      (xc < 0.1) q.p = 1000.0;
        else if (xc < 0.9) q.p = 0.01;
        else               q.p = 100.0;
        q.T = q.p / (q.rho * R_GAS);
        q.c = std::sqrt(GAMMA * q.p / q.rho);
        return q;
    };

    NSSolver s;
    s.cfg.bc_variant = WallBC{};
    s.cfg.cfl             = 0.4;
    s.cfg.regrid_interval = 0;
    s.cfg.max_level       = 0;
    s.cfg.verbose         = false;
    s.init(L, wc_ic);

    // Level-3 uniform refinement → 64 interior cells in x, h ≈ 0.015625
    for (int lvl = 0; lvl < 3; ++lvl) {
        auto lv = s.tree.leaf_indices();
        for (int li : lv) s.tree.refine(li);
        s.tree.rebuild_neighbours();
    }
    fill_leaves(s, wc_ic);
    s.alloc_scratch();

    // ── Initial mass ─────────────────────────────────────────────────────────
    double mass0 = 0.0;
    for (int li : s.tree.leaf_indices()) {
        const auto& blk = *s.tree.nodes[li].block;
        const double h3 = blk.h * blk.h * blk.h;
        for (int k = NG; k < NG+NB; ++k)
        for (int j = NG; j < NG+NB; ++j)
        for (int i = NG; i < NG+NB; ++i)
            mass0 += blk.Q[0][cell_idx(i,j,k)] * h3;
    }

    s.cfg.t_end    = 0.038;
    s.cfg.max_steps = 100000;
    s.run();

    auto prof = x_profile(s);

    // Unique-x profile
    std::vector<CellSample> ux;
    { double lx = -1e30;
      for (auto& pt : prof)
          if (pt.x > lx + 1e-14) { ux.push_back(pt); lx = pt.x; }
    }

    // ── B5a,b: max density location ──────────────────────────────────────────
    double rho_max = 0.0;
    double x_peak  = 0.0;
    for (auto& pt : ux) {
        if (pt.rho > rho_max) { rho_max = pt.rho; x_peak = pt.x; }
    }

    // ── B5c: min pressure ────────────────────────────────────────────────────
    double p_min = 1e30;
    for (auto& pt : ux) p_min = std::min(p_min, pt.p_gas);

    // ── B5d: mass conservation ───────────────────────────────────────────────
    double mass1 = 0.0;
    for (int li : s.tree.leaf_indices()) {
        const auto& blk = *s.tree.nodes[li].block;
        const double h3 = blk.h * blk.h * blk.h;
        for (int k = NG; k < NG+NB; ++k)
        for (int j = NG; j < NG+NB; ++j)
        for (int i = NG; i < NG+NB; ++i)
            mass1 += blk.Q[0][cell_idx(i,j,k)] * h3;
    }
    double mass_err = std::fabs(mass1 - mass0) / std::fabs(mass0);

    double h_cell = s.tree.nodes[s.tree.leaf_indices()[0]].block->h;
    printf("   t_final = %.4f  leaves = %d  h = %.6f\n",
           s.t, (int)s.tree.leaf_indices().size(), h_cell);
    printf("   ρ_max = %.4f at x = %.4f  (ref ≈ 6.0 at x ≈ 0.63 with >800 cells)\n",
           rho_max, x_peak);
    printf("   p_min = %.4e  mass_err = %.2e\n", p_min, mass_err);

    check("B5a  ρ_max > 3.0  (blast interaction)",
          rho_max > 3.0, rho_max, 3.0);
    check("B5b  x_peak ∈ [0.35, 0.85]",
          x_peak >= 0.35 && x_peak <= 0.85, x_peak, 0.63);
    check("B5c  no negative pressure  (p ratio 10⁵ robustness)",
          p_min > 0.0, p_min, 0.0);
    check("B5d  mass conservation < 1e-10  (closed domain)",
          mass_err < 1e-10, mass_err, 1e-10);
}

// ─────────────────────────────────────────────────────────────────────────────
int main()
{
    printf("=== B.5 gate: Woodward-Colella double blast waves ===\n");
    printf("  NB=%d  NG=%d  NB2=%d  NCELL=%d\n", NB, NG, NB2, NCELL);
    b5_woodward_colella();
    printf("\nResults: %d passed, %d failed\n", n_pass, n_fail);
    if (n_fail == 0) printf("==> PASS  B.5 gate cleared\n");
    else             printf("==> FAIL\n");
    return n_fail ? 1 : 0;
}
